5) Palindrome

let num = 121;
let temp = num;
let reverse = 0;

while (num > 0) {
 let digit = num % 10;
 reverse = reverse * 10 + digit;
 num = Math.floor(num / 10);
}

if (temp === reverse) {
 console.log("Palindrome");
} else {
 console.log("Not Palindrome");
}

